namespace sv_9f77b6f38f3741798c0ce6e5aa7ed18d.Services;

public class WarehouseState
{
    public static readonly (string Id, string Name)[] Warehouses =
    [
        ("wh-east", "Warehouse East"),
        ("wh-west", "Warehouse West"),
        ("wh-central", "Warehouse Central"),
    ];

    private string _currentWarehouseId = Warehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        Array.Find(Warehouses, w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

