@using sv_9f77b6f38f3741798c0ce6e5aa7ed18d.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount.HasValue && _lowStockCount.Value > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@_lowStockCount</span>
}
else if (_lowStockCount.HasValue)
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    private int? _lowStockCount;
    private CancellationTokenSource? _cts;

    /// <summary>
    /// When true, this instance owns its own polling loop.
    /// When false, it relies on external refresh calls (e.g. from the dashboard).
    /// </summary>
    [Parameter] public bool Poll { get; set; }

    /// <summary>
    /// Polling interval in milliseconds.
    /// </summary>
    [Parameter] public int IntervalMs { get; set; } = 10_000;

    /// <summary>
    /// Raised whenever new alert data is fetched, allowing sibling components to refresh.
    /// </summary>
    [Parameter] public EventCallback<int> OnAlertUpdated { get; set; }

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAsync();

        if (Poll)
        {
            StartPolling();
        }
    }

    public async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        await OnAlertUpdated.InvokeAsync(_lowStockCount.Value);
        StateHasChanged();
    }

    private void OnWarehouseChanged()
    {
        _ = InvokeAsync(async () =>
        {
            // Restart polling with new warehouse
            StopPolling();
            await RefreshAsync();
            if (Poll)
            {
                StartPolling();
            }
        });
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(IntervalMs, ct);
                await InvokeAsync(async () => await RefreshAsync());
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

