@page "/dashboard"
@rendermode InteractiveServer
@using sv_9f77b6f38f3741798c0ce6e5aa7ed18d.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Managing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="display-4 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @(_lowStockCount?.ToString() ?? "—")
                </p>
                <p class="text-muted mb-0">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mb-0">
                    <span class="badge bg-success">● Live</span>
                    every 10 seconds
                </p>
                @if (_lastChecked.HasValue)
                {
                    <small class="text-muted">Last checked: @_lastChecked.Value.ToString("HH:mm:ss")</small>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private DateTime? _lastChecked;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await FetchAlerts();
        StartPolling();
    }

    private async Task FetchAlerts()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
    }

