namespace sv_9f77b6f38f3741798c0ce6e5aa7ed18d.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Fired whenever a low-stock count is fetched, carrying (warehouseId, count).
    /// Other components can subscribe to stay in sync without polling themselves.
    /// </summary>
    public event Action<string, int>? OnLowStockCountFetched;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query for items below minimum stock levels
        var count = _random.Next(0, 16);
        OnLowStockCountFetched?.Invoke(warehouseId, count);
        return Task.FromResult(count);
    }
}

